class ItemInstance extends Model{use HasFactory;protected $guarded=[];protected $casts=['refinement_level'=>'integer','acquired_at'=>'datetime'];protected static function booted(){static::creating(function($m){$valid=$m->character_id&&$m->item_id&&$m->uuid&&$m->origin_type&&$m->origin_id&&$m->origin_unit_index&&$m->acquired_at&&in_array($m->status,ItemInstanceStatus::values(),true)&&$m->refinement_level>=ItemInstanceLimits::MIN_REFINEMENT_LEVEL&&$m->refinement_level<=ItemInstanceLimits::MAX_REFINEMENT_LEVEL;if(!$valid)throw new LogicException('Invalid ItemInstance.');$item=Item::whereKey($m->item_id)->first();try{$unique=$item&&(new ItemClassification())->classify($item)===ItemClassification::UNIQUE;}catch(\InvalidArgumentException $e){$unique=false;}if(!$unique)throw new LogicException('ItemInstance requires a coherent unique Item.');});static::updating(function($m){foreach(['uuid','origin_type','origin_id','origin_unit_index','acquired_at'] as $field)if($m->isDirty($field))throw new LogicException('ItemInstance identity and origin are immutable.');if($m->isDirty('status')&&!in_array($m->status,ItemInstanceStatus::values(),true))throw new LogicException('Invalid ItemInstance status.');if($m->isDirty('refinement_level')&&((int)$m->refinement_level<ItemInstanceLimits::MIN_REFINEMENT_LEVEL||(int)$m->refinement_level>ItemInstanceLimits::MAX_REFINEMENT_LEVEL))throw new LogicException('Invalid ItemInstance refinement level.');});}public function getRouteKeyName(){return'uuid';}public function character(){return$this->belongsTo(Character::class);}public function item(){return$this->belongsTo(Item::class);}public function events(){return$this->hasMany(ItemInstanceEvent::class);}public function equipment(){return$this->hasOne(CharacterEquipment::class);}}
